package com.enigma.familylinklite;

import android.Manifest;import android.app.*;import android.app.admin.DevicePolicyManager;import android.content.*;import android.graphics.*;import android.media.*;import android.net.wifi.WifiManager;import android.os.*;import android.provider.Settings;import android.text.InputType;import android.text.format.Formatter;import android.view.*;import android.widget.*;import com.google.zxing.*;import com.google.zxing.common.BitMatrix;import com.google.zxing.integration.android.IntentIntegrator;import com.google.zxing.integration.android.IntentResult;import org.json.*;import java.io.*;import java.net.*;import java.nio.charset.StandardCharsets;import java.security.*;import java.util.*;import javax.crypto.*;import javax.crypto.spec.*;

public class MainActivity extends Activity{
    static final int PORT=45454; LinearLayout root; byte[] key; String childIp=""; TextView log; BroadcastReceiver br; int parentVolume=50; Thread discoveryListenThread;
    public void onCreate(Bundle b){super.onCreate(b); getWindow().setSoftInputMode(WindowManager.LayoutParams.SOFT_INPUT_ADJUST_RESIZE); if(Build.VERSION.SDK_INT>=33)requestPermissions(new String[]{Manifest.permission.POST_NOTIFICATIONS},7); showStartOrSaved();}
    void showStartOrSaved(){String role=getSharedPreferences("p",0).getString("role","");String savedIp=getSharedPreferences("p",0).getString("childIp","");String savedKey=getSharedPreferences("p",0).getString("parentKey","");if(role.equals("parent")&&savedIp.length()>0&&savedKey.length()>0){childIp=savedIp;try{key=Base64.getDecoder().decode(savedKey);}catch(Exception ignored){}showConnectedParent(false);}else showStart();}
    protected void onDestroy(){try{if(br!=null)unregisterReceiver(br);}catch(Exception ignored){}super.onDestroy();}
    TextView tv(String s,int sp){TextView v=new TextView(this);v.setText(s);v.setTextSize(sp);v.setPadding(18,12,18,12);return v;}
    Button btn(String s){Button b=new Button(this);b.setText(s);b.setAllCaps(false);return b;}
    EditText edit(String hint){EditText e=new EditText(this);e.setHint(hint);e.setSingleLine(false);e.setMinLines(2);e.setPadding(18,12,18,12);return e;}
    void base(String title){ScrollView sv=new ScrollView(this);root=new LinearLayout(this);root.setOrientation(LinearLayout.VERTICAL);root.setPadding(24,32,24,32);sv.addView(root);setContentView(sv);root.addView(tv(title,24));log=tv("",14);}
    void showStart(){base("FamilyLink Lite");root.addView(tv("Install this same APK on both devices. Choose Parent on your phone and Child on the tablet.",16));Button p=btn("Parent phone");Button c=btn("Child tablet");root.addView(p);root.addView(c);p.setOnClickListener(v->{getSharedPreferences("p",0).edit().putString("role","parent").apply();showParentConnection();});c.setOnClickListener(v->{getSharedPreferences("p",0).edit().putString("role","child").apply();showChild();});}
    void showChild(){
        key=getOrCreateKey();base("Child tablet mode");String ip=getIp();String keyText=Base64.getEncoder().encodeToString(key);String pair=ip+":"+PORT+":"+keyText;int shortCode=checkCode(pair);String[] ipParts=ip.split("\\.");String prefix=ipParts.length==4?ipParts[0]+"."+ipParts[1]+"."+ipParts[2]+".":"";String last=ipParts.length==4?ipParts[3]:ip;
        root.addView(tv("Same Wi-Fi IP: "+ip,16));
        root.addView(tv("Manual connection: prefix "+prefix+" + last number "+last,16));
        root.addView(tv("5-digit check code: "+shortCode,22));
        root.addView(tv("Pairing secret for manual entry:",16));
        TextView keyView=tv(keyText,13);keyView.setTextIsSelectable(true);root.addView(keyView);
        root.addView(tv("The QR and full code contain the same connection information.",16));
        TextView code=tv(pair,13);code.setTextIsSelectable(true);root.addView(code);
        ImageView qr=new ImageView(this);qr.setImageBitmap(qrBitmap(pair,600));root.addView(qr);
        Button start=btn("Start / restart child background server");Button stop=btn("Stop child background server");Button usage=btn("Open Usage Access settings");Button admin=btn("Enable device admin");root.addView(start);root.addView(stop);root.addView(usage);root.addView(admin);
        usage.setOnClickListener(v->startActivity(new Intent(Settings.ACTION_USAGE_ACCESS_SETTINGS)));
        admin.setOnClickListener(v->startActivity(new Intent(DevicePolicyManager.ACTION_ADD_DEVICE_ADMIN).putExtra(DevicePolicyManager.EXTRA_DEVICE_ADMIN,new ComponentName(this,AdminReceiver.class))));
        start.setOnClickListener(v->startChildService());stop.setOnClickListener(v->{stopService(new Intent(this,ChildServerService.class));out("Child background server stop requested");});
        root.addView(log);listenLogs();startChildService();
    }
    void startChildService(){getSharedPreferences("p",0).edit().putString("key",Base64.getEncoder().encodeToString(key)).apply();Intent i=new Intent(this,ChildServerService.class);if(Build.VERSION.SDK_INT>=26)startForegroundService(i);else startService(i);out("Child background server start requested");}
    void showParentConnection(){base("Connect parent phone");root.addView(tv("Choose one connection method. QR is easiest. Manual connection is available if camera scanning fails.",16));Button scan=btn("Scan tablet QR");root.addView(scan);scan.setOnClickListener(v->{requestPermissions(new String[]{Manifest.permission.CAMERA},8);IntentIntegrator integrator=new IntentIntegrator(this);integrator.setPrompt("Scan the QR shown on the child tablet");integrator.setBeepEnabled(false);integrator.setOrientationLocked(false);integrator.initiateScan();});
        String myIp=getIp();String[] parts=myIp.split("\\.");String prefix=parts.length==4?parts[0]+"."+parts[1]+"."+parts[2]+".":"192.168.1.";root.addView(tv("Manual connection",18));root.addView(tv("Detected Wi-Fi prefix: "+prefix,16));EditText lastOctet=new EditText(this);lastOctet.setHint("Tablet IP last number, e.g. 42");lastOctet.setInputType(InputType.TYPE_CLASS_NUMBER);root.addView(lastOctet);EditText secret=edit("Pairing secret from tablet");root.addView(secret);Button manual=btn("Connect manually");root.addView(manual);manual.setOnClickListener(v->{String ip=prefix+lastOctet.getText().toString().trim();String sec=secret.getText().toString().trim();saveConnection(ip,sec);});
        root.addView(tv("Alternative: paste full pairing code",18));EditText pairing=edit("ip:45454:pairingSecret");root.addView(pairing);Button connect=btn("Connect with full code");root.addView(connect);connect.setOnClickListener(v->{try{String[] p=pairing.getText().toString().trim().split(":");saveConnection(p[0],p[2]);}catch(Exception e){toast("Invalid pairing code");}});root.addView(log);}
    void saveConnection(String ip,String secret){try{byte[] decoded=Base64.getDecoder().decode(secret);childIp=ip;key=decoded;getSharedPreferences("p",0).edit().putString("role","parent").putString("childIp",childIp).putString("parentKey",secret).apply();toast("Connection saved");showConnectedParent(true);}catch(Exception e){toast("Invalid pairing secret");out("Invalid pairing secret: "+e.getMessage());}}
    protected void onActivityResult(int requestCode,int resultCode,Intent data){IntentResult result=IntentIntegrator.parseActivityResult(requestCode,resultCode,data);if(result!=null){if(result.getContents()!=null){try{String[] p=result.getContents().trim().split(":");saveConnection(p[0],p[2]);}catch(Exception e){toast("Invalid QR code");}}else toast("QR scan cancelled");return;}super.onActivityResult(requestCode,resultCode,data);}
    void showConnectedParent(boolean tryNow){base("Parent connected screen");LinearLayout top=new LinearLayout(this);top.setOrientation(LinearLayout.HORIZONTAL);TextView status=tv("Disconnected",18);status.setBackgroundColor(Color.rgb(255,210,210));Button refresh=btn("↻");Button add=btn("+");top.addView(status,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));top.addView(refresh);top.addView(add);root.addView(top);root.addView(tv("Child tablet: "+childIp,16));TextView screen=tv("Today screen time: --:--",18);root.addView(screen);TextView apps=tv("Most active apps:\n1. --\n2. --\n3. --",16);root.addView(apps);add.setOnClickListener(v->showParentConnection());refresh.setOnClickListener(v->{status.setText("Connecting...");cmdWithCallback("usage","today",resp->{status.setText("Connected");status.setBackgroundColor(Color.rgb(210,255,210));updateUsageViews(resp,screen,apps);},err->{status.setText("Disconnected");status.setBackgroundColor(Color.rgb(255,210,210));out(err);});});
        root.addView(tv("Commands",18));LinearLayout volRow=new LinearLayout(this);volRow.setOrientation(LinearLayout.HORIZONTAL);Button down=btn("Volume -");Button up=btn("Volume +");Button mute=btn("Mute");volRow.addView(down,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));volRow.addView(up,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));volRow.addView(mute,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));root.addView(volRow);TextView volLabel=tv("Current requested volume: "+parentVolume+"%",16);root.addView(volLabel);down.setOnClickListener(v->{parentVolume=Math.max(0,parentVolume-10);volLabel.setText("Current requested volume: "+parentVolume+"%");cmd("volume",String.valueOf(parentVolume));});up.setOnClickListener(v->{parentVolume=Math.min(100,parentVolume+10);volLabel.setText("Current requested volume: "+parentVolume+"%");cmd("volume",String.valueOf(parentVolume));});mute.setOnClickListener(v->{parentVolume=0;volLabel.setText("Current requested volume: 0%");cmd("volume","0");});EditText msg=edit("Message to child");root.addView(msg);Button send=btn("Send message");Button ping=btn("Ping / make sound");Button stop=btn("Stop ping");Button usage=btn("Refresh usage");for(Button b:new Button[]{send,ping,stop,usage})root.addView(b);send.setOnClickListener(v->cmd("message",msg.getText().toString()));ping.setOnClickListener(v->cmd("ping","start"));stop.setOnClickListener(v->cmd("ping","stop"));usage.setOnClickListener(v->refresh.performClick());root.addView(log);startDiscoveryListener();if(tryNow)refresh.performClick();}
    void updateUsageViews(String resp,TextView screen,TextView apps){long total=0;String[] lines=resp.split("\\n");StringBuilder top=new StringBuilder("Most active apps:\n");int n=0;for(String line:lines){if(!line.contains(": ")||!line.endsWith(" min"))continue;try{long mins=Long.parseLong(line.substring(line.indexOf(": ")+2,line.indexOf(" min")).trim());total+=mins;if(n<3){top.append(n+1).append(". ").append(line).append("\n");n++;}}catch(Exception ignored){}}screen.setText(String.format(Locale.US,"Today screen time: %02d:%02d",total/60,total%60));while(n<3){top.append(n+1).append(". --\n");n++;}apps.setText(top.toString());}

    void startDiscoveryListener(){if(discoveryListenThread!=null&&discoveryListenThread.isAlive())return;discoveryListenThread=new Thread(()->{try{DatagramSocket ds=new DatagramSocket(45455);byte[] buf=new byte[512];while(true){DatagramPacket p=new DatagramPacket(buf,buf.length);ds.receive(p);String msg=new String(p.getData(),0,p.getLength(),StandardCharsets.UTF_8);String[] parts=msg.split("\\|");if(parts.length>=4&&parts[0].equals("FLITE")&&parts[3].equals(pairingId())){String ip=p.getAddress().getHostAddress();if(!ip.equals(childIp)){childIp=ip;getSharedPreferences("p",0).edit().putString("childIp",childIp).apply();out("Child rediscovered at "+childIp);}}}}catch(Exception ignored){}},"FamilyLinkDiscoveryListen");discoveryListenThread.start();}
    String pairingId(){try{MessageDigest md=MessageDigest.getInstance("SHA-256");byte[] h=md.digest(key);return Base64.getEncoder().encodeToString(Arrays.copyOf(h,9));}catch(Exception e){return "unknown";}}
    interface Ok{void call(String s);} interface Err{void call(String s);}
    void cmd(String type,String value){cmdWithCallback(type,value,resp->out(resp),err->out(err));}
    void cmdWithCallback(String type,String value,Ok ok,Err err){new Thread(()->{try{if(childIp.length()==0||key==null){runOnUiThread(()->err.call("No child connection saved"));return;}JSONObject j=new JSONObject();j.put("type",type);j.put("value",value);Socket s=new Socket();s.connect(new InetSocketAddress(childIp,PORT),2500);PrintWriter w=new PrintWriter(s.getOutputStream(),true);w.println(encrypt(j.toString()));BufferedReader r=new BufferedReader(new InputStreamReader(s.getInputStream()));String resp=decrypt(r.readLine());s.close();runOnUiThread(()->ok.call(resp));}catch(Exception e){runOnUiThread(()->err.call("Command failed: "+e.getMessage()+"\nCheck that the tablet app is in Child mode, the child server notification is visible, and both devices are on the same Wi-Fi."));}}).start();}
    int checkCode(String s){return Math.abs(s.hashCode())%90000+10000;}
    byte[] getOrCreateKey(){String saved=getSharedPreferences("p",0).getString("key",null);if(saved!=null)return Base64.getDecoder().decode(saved);byte[] b=new byte[32];new SecureRandom().nextBytes(b);getSharedPreferences("p",0).edit().putString("key",Base64.getEncoder().encodeToString(b)).apply();return b;}
    String encrypt(String plain)throws Exception{byte[] iv=new byte[12];new SecureRandom().nextBytes(iv);Cipher c=Cipher.getInstance("AES/GCM/NoPadding");c.init(Cipher.ENCRYPT_MODE,new SecretKeySpec(key,"AES"),new GCMParameterSpec(128,iv));byte[] enc=c.doFinal(plain.getBytes(StandardCharsets.UTF_8));byte[] all=new byte[iv.length+enc.length];System.arraycopy(iv,0,all,0,iv.length);System.arraycopy(enc,0,all,iv.length,enc.length);return Base64.getEncoder().encodeToString(all);} 
    String decrypt(String data)throws Exception{byte[] all=Base64.getDecoder().decode(data);byte[] iv=Arrays.copyOfRange(all,0,12);byte[] enc=Arrays.copyOfRange(all,12,all.length);Cipher c=Cipher.getInstance("AES/GCM/NoPadding");c.init(Cipher.DECRYPT_MODE,new SecretKeySpec(key,"AES"),new GCMParameterSpec(128,iv));return new String(c.doFinal(enc),StandardCharsets.UTF_8);} 
    String getIp(){try{WifiManager wm=(WifiManager)getApplicationContext().getSystemService(WIFI_SERVICE);return Formatter.formatIpAddress(wm.getConnectionInfo().getIpAddress());}catch(Exception e){return "0.0.0.0";}}
    Bitmap qrBitmap(String text,int size){try{BitMatrix m=new MultiFormatWriter().encode(text,BarcodeFormat.QR_CODE,size,size);Bitmap bmp=Bitmap.createBitmap(size,size,Bitmap.Config.RGB_565);for(int x=0;x<size;x++)for(int y=0;y<size;y++)bmp.setPixel(x,y,m.get(x,y)?Color.BLACK:Color.WHITE);return bmp;}catch(Exception e){Bitmap b=Bitmap.createBitmap(10,10,Bitmap.Config.RGB_565);b.eraseColor(Color.LTGRAY);return b;}}
    void listenLogs(){try{if(br!=null)unregisterReceiver(br);}catch(Exception ignored){}br=new BroadcastReceiver(){public void onReceive(Context c,Intent i){out(i.getStringExtra("msg"));}};if(Build.VERSION.SDK_INT>=33)registerReceiver(br,new IntentFilter("com.enigma.familylinklite.LOG"),RECEIVER_NOT_EXPORTED);else registerReceiver(br,new IntentFilter("com.enigma.familylinklite.LOG"));}
    void out(String s){runOnUiThread(()->{log.setText(s+"\n\n"+log.getText());});}
    void toast(String s){Toast.makeText(this,s,Toast.LENGTH_SHORT).show();}
}
